Here’s a simple example of a basic Chrome Extension for a task list (similar to the one created by @miams). This includes the necessary files:

**manifest.json**

{
  "manifest_version": 3,
  "name": "Minimalist Task List",
  "version": "1.0",
  "description": "A simple Yes/No task list for Chrome.",
  "action": {
    "default_popup": "popup.html",
    "default_icon": "icon.png"
  },
  "permissions": ["storage"]
}


**popup.html**
html
<!DOCTYPE html>
<html>
<head>
  <title>Task List</title>
  <style>
    body { width: 200px; padding: 10px; }
    input { width: 100%; }
    button { margin-top: 10px; }
    #tasks { margin-top: 10px; }
  </style>
</head>
<body>
  <h3>Task List</h3>
  <input type="text" id="taskInput" placeholder="Add a task">
  <button id="addTask">Add</button>
  <div id="tasks"></div>
  <script src="popup.js"></script>
</body>
</html>


**popup.js**
javascript
document.getElementById('addTask').addEventListener('click', addTask);

function addTask() {
  const taskInput = document.getElementById('taskInput');
  const taskText = taskInput.value.trim();
  if (taskText) {
    const tasks = JSON.parse(localStorage.getItem('tasks') || '[]');
    tasks.push({ text: taskText, done: false });
    localStorage.setItem('tasks', JSON.stringify(tasks));
    renderTasks();
    taskInput.value = '';
  }
}

function renderTasks() {
  const tasksContainer = document.getElementById('tasks');
  tasksContainer.innerHTML = '';
  const tasks = JSON.parse(localStorage.getItem('tasks') || '[]');
  tasks.forEach((task, index) => {
    const taskElement = document.createElement('div');
    taskElement.textContent = task.text;
    taskElement.style.textDecoration = task.done ? 'line-through' : 'none';
    taskElement.addEventListener('click', () => {
      task.done = !task.done;
      localStorage.setItem('tasks', JSON.stringify(tasks));
      renderTasks();
    });
    tasksContainer.appendChild(taskElement);
  });
}

renderTasks();

This extension allows users to add tasks, mark them as done, and stores them locally.
